CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_hypotheses (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, user_id INTEGER NOT NULL, process_id INTEGER, title TEXT NOT NULL, description TEXT, hypothesis_type TEXT NOT NULL DEFAULT 'automation', expected_effect TEXT, validation_method TEXT, data_needed TEXT, risk_notes TEXT, owner_name TEXT, due_date DATE, status TEXT NOT NULL DEFAULT 'new', confidence_level TEXT NOT NULL DEFAULT 'low', result_summary TEXT, decision TEXT, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_hypo_case ON t_p61016064_digital_innovation_i.wb_hypotheses(case_id); CREATE INDEX IF NOT EXISTS idx_wb_hypo_status ON t_p61016064_digital_innovation_i.wb_hypotheses(status);